/// <summary>
/// When <c>JmgProductionFloorExecutionInfoMessageMenuItemFlight</c> is enabled, menu items will be used for opening message forms
/// on the Production Floor Execution.
/// </summary>
/// <remarks>
/// The flight is controlled by entering the following in the flighting service (Carbon or similar):
/// "JmgProductionFloorExecutionInfoMessageMenuItemFlight" to enable. This is only necessary when isEnabledByDefault() returns false.
/// "JmgProductionFloorExecutionInfoMessageMenuItemFlight_KillSwitch" to disable. This overrules any enablement.
/// </remarks>
internal final class KPMGCommon_JmgProductionFloorExecutionInfoMessageMenuItemFlight extends Flight
{
    static private KPMGCommon_JmgProductionFloorExecutionInfoMessageMenuItemFlight singleton = new KPMGCommon_JmgProductionFloorExecutionInfoMessageMenuItemFlight();

}
